import usocket as socket
import ustruct as struct
import machine
import json

# WebSocket opcodes
OPCODE_TEXT = 0x1
OPCODE_CLOSE = 0x8

def websocket_handshake(sock, client):
    # Read HTTP headers until empty line is received
    request = b""
    while True:
        line = client.readline()
        if not line or line == b"\r\n":
            break
        request += line

    # Send WebSocket handshake response
    handshake_response = (
        b"HTTP/1.1 101 Switching Protocols\r\n"
        b"Upgrade: websocket\r\n"
        b"Connection: Upgrade\r\n"
        b"Sec-WebSocket-Accept: s3pPLMBiTxaQ9kYGzzhZRbK+xOo=\r\n\r\n"
    )
    client.write(handshake_response)

def websocket_send(client, message):
    # Create WebSocket frame for text message
    payload = message.encode('utf-8')
    header = struct.pack("!BB", (1 << 7) | OPCODE_TEXT, len(payload))
    client.write(header + payload)

def websocket_receive(client):
    # Read WebSocket frame
    first_byte = ord(client.read(1))
    opcode = first_byte & 0x0F

    if opcode == OPCODE_CLOSE:
        return None, "Connection closed"

    length_byte = ord(client.read(1))
    mask = (length_byte >> 7) & 1
    payload_length = length_byte & 0x7F

    if payload_length == 126:
        extended_payload_length = struct.unpack("!H", client.read(2))[0]
    elif payload_length == 127:
        extended_payload_length = struct.unpack("!Q", client.read(8))[0]
    else:
        extended_payload_length = payload_length

    masking_key = b""
    if mask:
        masking_key = client.read(4)

    payload = bytearray(client.read(extended_payload_length))
    if mask:
        for i in range(len(payload)):
            payload[i] ^= ord(masking_key[i % 4])

    return json.loads(payload.decode('utf-8')), None

def main():
    # Initialize GPIO
    led = machine.Pin(2, machine.Pin.OUT)

    # Create socket and bind it to port 80
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.bind(("0.0.0.0", 80))
    s.listen(5)

    while True:
        print("Waiting for connection...")
        client, addr = s.accept()
        print("Connection from:", addr)

        websocket_handshake(s, client)

        while True:
            message, error = websocket_receive(client)
            if error:
                print(error)
                break

            action = message.get('action')
            if action == "turn_on":
                led.value(1)
                websocket_send(client, json.dumps({"status": "LED turned on"}))
            elif action == "turn_off":
                led.value(0)
                websocket_send(client, json.dumps({"status": "LED turned off"}))

        client.close()

if __name__ == "__main__":
    main()